from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize aggregation structure
    aggregated = defaultdict(lambda: {
        'scores': [],
        'custom': {}
    })

    # Helper function to safely get metadata values
    def get_metadata_value(result: SearchResult, field: str) -> Any:
        """Safely extract metadata value with proper None handling"""
        if hasattr(result, 'metadata') and result.metadata is not None:
            return result.metadata.get(field)
        return None

    # Process each search result
    for result in search_results:
        # Extract group value from metadata
        group_value = get_metadata_value(result, group_by_field)

        # Handle missing group values
        if group_value is None or group_value == "":
            group_value = 'unknown'

        # Collect scores for default statistics
        aggregated[group_value]['scores'].append(result.score)

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field, func in aggregation_funcs.items():
                # Get field value (check both top-level attributes and metadata)
                field_value = None

                # Check top-level attributes first
                if hasattr(result, field):
                    field_value = getattr(result, field)

                # Fall back to metadata if not found at top level
                if field_value is None:
                    field_value = get_metadata_value(result, field)

                # Collect value for aggregation
                if field_value is not None:
                    aggregated[group_value]['custom'].setdefault(field, []).append(field_value)

    # Build final aggregated results with proper statistics calculation
    final_results = {}

    for group_value, data in aggregated.items():
        # Calculate default statistics
        stats = {}
        scores = data['scores']

        if scores:
            stats['count'] = len(scores)
            stats['avg_score'] = sum(scores) / len(scores)
            stats['max_score'] = max(scores)
            stats['min_score'] = min(scores)
        else:
            stats['count'] = 0
            stats['avg_score'] = 0.0
            stats['max_score'] = 0.0
            stats['min_score'] = 0.0

        # Apply custom aggregation functions
        if aggregation_funcs and data['custom']:
            for field, values in data['custom'].items():
                if values:
                    try:
                        stats[field] = func(values)
                    except Exception as e:
                        # Handle potential errors in custom aggregation functions
                        stats[field] = f"Error: {str(e)}"

        final_results[group_value] = stats

    return final_results

